USE fund_together;

INSERT INTO project (sponsor_id, category_id, title, summary, cover_image, content, target_amount, current_amount, supporter_count, start_time, end_time, status, heat, created_at, updated_at) VALUES 
(1, 1, '智能脑机接口睡眠仪', '通过非侵入式脑电波监测与神经反馈，为你定制个性化的深度睡眠解决方案。', 'https://images.unsplash.com/photo-1550751827-4bd374c3f58b?auto=format&fit=crop&w=800&q=80', '<p><strong>产品理念：</strong> 现代社会压力巨大，睡眠障碍成为许多人的困扰。我们研发的智能脑机接口睡眠仪采用医疗级EEG传感技术，精准捕捉您的睡眠周期。</p><p><strong>核心技术：</strong> 独家神经调控算法、声光电全方位干预、实时APP数据分析。</p><p><strong>为什么需要您的支持：</strong> 我们已经完成原型机测试，这笔资金将用于小批量试产及医疗器械认证。</p>', 200000.00, 0.00, 0, NOW(), DATE_ADD(NOW(), INTERVAL 60 DAY), 1, 350, NOW(), NOW()),
(1, 1, '家用微型水培蔬菜机', '将农场搬进厨房，全自动光照与营养液循环，让都市家庭也能吃上现摘的有机蔬菜。', 'https://images.unsplash.com/photo-1530836369250-ef71a3f5e481?auto=format&fit=crop&w=800&q=80', '<p><strong>产品特色：</strong> 占地仅0.2平方米，可同时培育20株水培植物。内置全光谱LED补光灯与智能水循环系统。</p><p><strong>零门槛种植：</strong> APP一键选择植物种类，系统自动配置营养液浓度和光照时间，傻瓜式操作。</p><p><strong>众筹目的：</strong> 筹集首批开模和量产资金，支持者将获得首发早鸟价及一年份营养液包。</p>', 150000.00, 0.00, 0, NOW(), DATE_ADD(NOW(), INTERVAL 60 DAY), 1, 280, NOW(), NOW()),
(1, 1, '模块化编程无人机', '专为青少年设计的可重组无人机，支持Python/Scratch编程，寓教于乐。', 'https://images.unsplash.com/photo-1527977966376-1c8408f9f108?auto=format&fit=crop&w=800&q=80', '<p><strong>不仅是玩具：</strong> 采用碳纤维抗摔材质，配备高清摄像头、超声波避障模块。支持上百种拼装形态。</p><p><strong>STEM教育神器：</strong> 附赠完整的由浅入深的编程课程，让孩子在飞行中掌握代码逻辑。</p><p><strong>项目进度：</strong> 软硬件设计均已冻结，正处于供应链打样阶段，期待您的助力让科技走进更多家庭。</p>', 300000.00, 0.00, 0, NOW(), DATE_ADD(NOW(), INTERVAL 60 DAY), 1, 410, NOW(), NOW()),
(1, 1, '便携式海水淡化杯', '户外探险与应急救援的生命之源，太阳能驱动，1小时可净化500ml海水或污水。', 'https://images.unsplash.com/photo-1558449028-b53a39d100fc?auto=format&fit=crop&w=800&q=80', '<p><strong>极限环境求生：</strong> 采用多层反渗透膜与紫外线杀菌技术，仅重450g，可轻松挂在背包上。</p><p><strong>绿色能源：</strong> 顶部集成高效柔性太阳能板，有光即可工作，也可通过手摇发电应急。</p><p><strong>资金用途：</strong> 投入滤芯的大规模量产及各项严苛的国际水质安全认证。</p>', 500000.00, 0.00, 0, NOW(), DATE_ADD(NOW(), INTERVAL 60 DAY), 1, 620, NOW(), NOW()),
(1, 1, 'AI宠物翻译项圈', '基于深度学习的声音与行为分析，让你真正听懂猫狗的心声。', 'https://images.unsplash.com/photo-1517849845537-4d257902454a?auto=format&fit=crop&w=800&q=80', '<p><strong>打破物种屏障：</strong> 收集超百万条宠物叫声样本，结合多轴陀螺仪捕捉的动作数据，准确率高达85%。</p><p><strong>健康监测：</strong> 实时记录宠物运动量、心率与睡眠，异常情况APP即时预警。</p><p><strong>我们的愿景：</strong> 让人类与毛孩子建立更深的羁绊。您的支持将帮助我们优化AI模型并完成首批量产。</p>', 100000.00, 0.00, 0, NOW(), DATE_ADD(NOW(), INTERVAL 60 DAY), 1, 890, NOW(), NOW()),

(1, 2, '大凉山古法红糖振兴计划', '传承百年手工熬糖工艺，帮助深山蔗农提高收入，将纯正的甘甜带给城市。', 'https://images.unsplash.com/photo-1582210815124-71ee5e76a601?auto=format&fit=crop&w=800&q=80', '<p><strong>项目背景：</strong> 大凉山深处有着优质的高山甘蔗，但因交通不便和销路不畅，许多老糖匠放弃了这门手艺。</p><p><strong>我们的行动：</strong> 建立标准化卫生生产车间，统一收购、包装、物流。保留十八道古法工序，绝不添加防腐剂和色素。</p><p><strong>社会效益：</strong> 预计直接带动当地50户贫困家庭增收。您的每一次支持，都是对传统手艺的守护。</p>', 50000.00, 0.00, 0, NOW(), DATE_ADD(NOW(), INTERVAL 60 DAY), 1, 550, NOW(), NOW()),
(1, 2, '认养一棵沙漠苹果树', '在新疆阿拉尔沙漠边缘种下一棵苹果树，防风固沙的同时收获冰糖心苹果。', 'https://images.unsplash.com/photo-1611080626919-7cf5a9db4024?auto=format&fit=crop&w=800&q=80', '<p><strong>荒漠绿洲：</strong> 这里日照长、温差大，是种植冰糖心苹果的绝佳之地，也是阻挡塔克拉玛干沙漠扩张的防线。</p><p><strong>认养模式：</strong> 支持者将获得一棵树的专属挂牌，通过小程序实时查看生长情况，秋季丰收时包邮到家。</p><p><strong>环保与扶贫双赢：</strong> 资金将用于滴灌系统建设及雇佣当地农民进行日常管护。</p>', 80000.00, 0.00, 0, NOW(), DATE_ADD(NOW(), INTERVAL 60 DAY), 1, 720, NOW(), NOW()),
(1, 2, '土家族高山冷水米推广', '一年仅产一季，富含硒元素。让深山里的优质冷水米走出大山。', 'https://images.unsplash.com/photo-1586201375761-83865001e8ac?auto=format&fit=crop&w=800&q=80', '<p><strong>珍稀品种：</strong> 种植于海拔1200米以上的梯田，由高山泉水灌溉，生长期长达150天，米粒修长、口感软糯。</p><p><strong>困境与突破：</strong> 传统散卖价格极低。我们计划打造地域品牌，引入真空包装技术，延长保质期。</p><p><strong>资金流向：</strong> 全部用于购买包装设备、支付农民保底收购价及初期品牌营销。</p>', 60000.00, 0.00, 0, NOW(), DATE_ADD(NOW(), INTERVAL 60 DAY), 1, 310, NOW(), NOW()),
(1, 2, '留守妇女手工竹编工坊', '授人以渔，为四川某贫困村的留守妇女提供竹编技能培训，让她们居家即可就业。', 'https://images.unsplash.com/photo-1520626786801-447547b52125?auto=format&fit=crop&w=800&q=80', '<p><strong>项目初衷：</strong> 为了照顾孩子和老人，许多妇女无法外出打工。当地盛产慈竹，有着悠久的竹编历史。</p><p><strong>工坊运作：</strong> 聘请非遗传承人进行系统培训，结合现代审美设计竹编包、茶具等文创产品。</p><p><strong>众筹目标：</strong> 筹集首批原材料采购费、导师课酬及首家线下体验店的装修费用。支持者将获得精美的纯手工竹编回馈。</p>', 40000.00, 0.00, 0, NOW(), DATE_ADD(NOW(), INTERVAL 60 DAY), 1, 480, NOW(), NOW()),
(1, 2, '原生态放养黑猪保种计划', '保护濒危的本土黑猪品种，坚持300天林间散养，拒绝饲料催肥。', 'https://images.unsplash.com/photo-1516467508483-a7212febe31a?auto=format&fit=crop&w=800&q=80', '<p><strong>物种危机：</strong> 受外来瘦肉型猪冲击，我国本土优良黑猪品种急剧减少。它们虽然长得慢，但肉质鲜美、大理石纹丰富。</p><p><strong>散养模式：</strong> 包裹万亩荒山作为牧场，黑猪自由采食野果野草，辅以农家粗粮，真正做到道法自然。</p><p><strong>支持我们：</strong> 您的资金将用于扩大繁育基地和建立冷链物流体系。支持者将享受年度新鲜黑猪肉的优先配送权。</p>', 120000.00, 0.00, 0, NOW(), DATE_ADD(NOW(), INTERVAL 60 DAY), 1, 390, NOW(), NOW()),

(1, 3, '《失落的文明》独立游戏开发', '一款基于中国神话体系的类魂动作RPG，用虚幻5引擎重塑山海经世界。', 'https://images.unsplash.com/photo-1552820728-8b83bb6b773f?auto=format&fit=crop&w=800&q=80', '<p><strong>游戏设定：</strong> 玩家将扮演一位上古遗民，在碎片化的叙事中探索宏大的东方奇幻神话，挑战上古异兽。</p><p><strong>核心玩法：</strong> 融合五行相生相克的硬核战斗系统，丰富的美术场景从昆仑雪山到东海归墟。</p><p><strong>团队现状：</strong> 我们是15人的全职独立团队。目前已完成核心Demo，众筹资金将用于外包部分动作捕捉和音乐音效制作。</p>', 500000.00, 0.00, 0, NOW(), DATE_ADD(NOW(), INTERVAL 60 DAY), 1, 950, NOW(), NOW()),
(1, 3, '寻访百位民间皮影艺人纪录片', '历时三年，跨越五省，记录光影背后的沧桑与传承，抢救即将消亡的民间艺术。', 'https://images.unsplash.com/photo-1518398046578-8cca57782e17?auto=format&fit=crop&w=800&q=80', '<p><strong>抢救性拍摄：</strong> 随着老艺人们的逐渐凋零，传统的皮影戏正面临失传。我们希望用镜头留下他们最后的影像与绝活。</p><p><strong>内容规划：</strong> 共10集，每集30分钟。不仅展现精美的雕刻工艺和唱腔，更深入探讨手艺人的生存现状。</p><p><strong>资金用途：</strong> 纪录片的后期剪辑、调色、原创配乐以及国内外电影节的投递发行。</p>', 150000.00, 0.00, 0, NOW(), DATE_ADD(NOW(), INTERVAL 60 DAY), 1, 460, NOW(), NOW()),
(1, 3, '沉浸式互动戏剧《梦回长安》', '打破舞台边界，在复原的唐代实景建筑中，观众与演员共同决定故事走向。', 'https://images.unsplash.com/photo-1499364615650-ec38552f4f34?auto=format&fit=crop&w=800&q=80', '<p><strong>全新观剧体验：</strong> 没有固定的座位，观众换上唐装，穿梭于酒肆、坊市与青楼之间，每个角色都有隐藏剧情。</p><p><strong>顶级主创：</strong> 由国内一线舞美团队操刀，结合全息投影与多声道环绕音效，真实还原盛唐气象。</p><p><strong>众筹回报：</strong> 资金用于服化道的最后完善。支持者可获得首演门票、专属NPC互动特权及定制周边纪念品。</p>', 300000.00, 0.00, 0, NOW(), DATE_ADD(NOW(), INTERVAL 60 DAY), 1, 680, NOW(), NOW()),
(1, 3, '赛博朋克风插画集《霓虹蜃楼》', '收录画师三年来的百幅心血之作，展现东方元素与未来科技碰撞的视觉奇观。', 'https://images.unsplash.com/photo-1542931287-023b922fa89b?auto=format&fit=crop&w=800&q=80', '<p><strong>作品亮点：</strong> 将传统中国古建、戏曲元素与义体改造、霓虹灯牌巧妙融合。全彩150克特种纸印刷，硬壳精装。</p><p><strong>创作历程：</strong> 每一幅画背后都有一个微小说设定，画集不仅是一场视觉盛宴，更是一个庞大的世界观设定集。</p><p><strong>为何众筹：</strong> 个人出版成本高昂，众筹资金将全部用于印刷制版。解锁目标后将增加烫镭射银工艺及附赠大海报。</p>', 80000.00, 0.00, 0, NOW(), DATE_ADD(NOW(), INTERVAL 60 DAY), 1, 810, NOW(), NOW()),
(1, 3, '复古机械键盘键帽设计计划', '以打字机与蒸汽朋克为灵感，采用金属与实木材质，打造指尖上的艺术品。', 'https://images.unsplash.com/photo-1595225476474-87563907a212?auto=format&fit=crop&w=800&q=80', '<p><strong>匠心打磨：</strong> 键帽主体由胡桃木CNC加工而成，外圈镶嵌黄铜电镀边框，经过数十次打样才确定最佳的指腹贴合弧度。</p><p><strong>兼容性：</strong> 适配市面上99%的十字轴体（如Cherry轴），支持104/87/68等多种配列。</p><p><strong>量产计划：</strong> 纯手工打磨成本过高，此次众筹将用于开模并引入半自动化生产线，大幅降低价格让更多人体验。</p>', 100000.00, 0.00, 0, NOW(), DATE_ADD(NOW(), INTERVAL 60 DAY), 1, 530, NOW(), NOW());
